// Create multiple test items with different service paths
// Tests that each item is processed with its own service path

return [
  {
    json: {
      servicePath: "/sap/opu/odata/sap/API_SALES_ORDER_SRV",
      entitySet: "SalesOrderSet",
      testName: "Item 1 - Sales Orders"
    }
  },
  {
    json: {
      servicePath: "/sap/opu/odata/sap/API_BUSINESS_PARTNER",
      entitySet: "A_BusinessPartner",
      testName: "Item 2 - Business Partners"
    }
  }
];

// Verify that each item was processed correctly
const items = $input.all();

return [
  {
    json: {
      test: "Multi-Item Execution",
      result: items.length === 2 ? "✅ PASSED" : "❌ FAILED",
      itemsProcessed: items.length,
      details: items.map((item, idx) => ({
        itemIndex: idx,
        testName: item.json._testName || `Item ${idx + 1}`,
        hasData: !!item.json.d || !!item.json.value,
        servicePath: item.json._servicePath || "unknown"
      })),
      explanation: "Each item should be processed with its own service path - no cache mixing!",
      expectedBehavior: "2 items processed, each with correct service path"
    }
  }
];
